// Non-default primary-key shapes and an enum default value:
//
//   - tWebhookEvent.id: `autogeneratedPrimaryKey('id', 'bigint')` — a bigint
//     autogenerated PK (vs the usual int IDENTITY/SERIAL).
//   - tCalendarYear.yearValue: `primaryKey('year_value', 'int')` — a
//     caller-provided int PK.
//   - tWebhookEvent.eventType: `columnWithDefaultValue('event_type', 'enum', ...)`
//     — an enum column with a DB DEFAULT.

import { afterAll, beforeAll, beforeEach, describe, expect, test } from '../../../../lib/testRunner.js'
import { assertType, type Exact } from '../../../../lib/assertType.js'
import { tCalendarYear, tWebhookEvent, type WebhookEventType } from '../../domain/connection.js'
import { ctx } from './setup.js'

describe(ctx.label, () => {
    beforeAll(() => ctx.up(), ctx.timeoutMs)
    afterAll(() => ctx.down(), ctx.timeoutMs)
    beforeEach(() => { ctx.reset() })

    test('bigint-autogenerated-pk-reads-as-bigint', async () => {
        // Seeded rows get auto ids 1n, 2n on a fresh DB; the bigint autogen PK
        // reads back as a `bigint`, not a `number`.
        const expected = [
            { id: 1n, eventType: 'created' as WebhookEventType },
            { id: 2n, eventType: 'updated' as WebhookEventType },
        ]
        ctx.mockNext(expected)
        const rows = await ctx.conn.selectFrom(tWebhookEvent)
            .select({ id: tWebhookEvent.id, eventType: tWebhookEvent.eventType })
            .orderBy('id')
            .executeSelectMany()

        expect(ctx.lastSql).toMatchInlineSnapshot(`"select id as id, event_type as eventType from webhook_event order by id"`)
        expect(ctx.lastParams).toMatchInlineSnapshot(`[]`)
        assertType<Exact<typeof rows, Array<{ id: bigint; eventType: WebhookEventType }>>>()
        expect(rows).toEqual(expected)
    })

    test('bigint-autogenerated-pk-insert-returns-bigint', async () => {
        // Inserting without id auto-generates the bigint PK;
        // `returningLastInsertedId` types the result as `bigint`.
        await ctx.withRollback(async () => {
            ctx.mockNext(3n)
            const newId = await ctx.conn.insertInto(tWebhookEvent)
                .set({ issueId: 1, eventType: 'deleted' })
                .returningLastInsertedId()
                .executeInsert()

            expect(ctx.lastSql).toMatchInlineSnapshot(`"insert into webhook_event (issue_id, event_type) values (?, ?) returning id"`)
            expect(ctx.lastParams).toMatchInlineSnapshot(`
              [
                1,
                "deleted",
              ]
            `)
            assertType<Exact<typeof newId, bigint>>()
            if (ctx.realDbEnabled) expect(typeof newId).toBe('bigint')
            else expect(newId).toBe(3n)
        })
    })

    test('enum-default-value-applies-when-column-omitted', async () => {
        // event_type is `columnWithDefaultValue('event_type','enum',...)`, so
        // omitting it on insert applies the DB DEFAULT 'created'.
        await ctx.withRollback(async () => {
            ctx.mockNext(4n)
            const newId = await ctx.conn.insertInto(tWebhookEvent)
                .set({ issueId: 2 })
                .returningLastInsertedId()
                .executeInsert()

            ctx.mockNext('created')
            const eventType = await ctx.conn.selectFrom(tWebhookEvent)
                .where(tWebhookEvent.id.equals(newId))
                .selectOneColumn(tWebhookEvent.eventType)
                .executeSelectOne()

            expect(ctx.lastSql).toMatchInlineSnapshot(`"select event_type as result from webhook_event where id = ?"`)
            expect(ctx.lastParams).toMatchInlineSnapshot(`
              [
                3n,
              ]
            `)
            assertType<Exact<typeof eventType, WebhookEventType>>()
            expect(eventType).toBe('created')
        })
    })

    test('int-provided-pk-reads', async () => {
        // calendar_year.yearValue is a caller-provided int PK; seeded 2023/2024.
        const expected = { yearValue: 2023, label: 'FY2023' }
        ctx.mockNext(expected)
        const row = await ctx.conn.selectFrom(tCalendarYear)
            .where(tCalendarYear.yearValue.equals(2023))
            .select({ yearValue: tCalendarYear.yearValue, label: tCalendarYear.label })
            .executeSelectOne()

        expect(ctx.lastSql).toMatchInlineSnapshot(`"select year_value as yearValue, year_label as label from calendar_year where year_value = ?"`)
        expect(ctx.lastParams).toMatchInlineSnapshot(`
          [
            2023,
          ]
        `)
        assertType<Exact<typeof row, { yearValue: number; label: string }>>()
        expect(row).toEqual(expected)
    })

    test('int-provided-pk-insert-requires-the-key', async () => {
        // The provided int PK is required on insert (it is in the writable
        // shape, unlike an autogenerated PK). Inserting a new year works.
        await ctx.withRollback(async () => {
            ctx.mockNext(1)
            const affected = await ctx.conn.insertInto(tCalendarYear)
                .values({ yearValue: 2030, label: 'FY2030' })
                .executeInsert()

            expect(ctx.lastSql).toMatchInlineSnapshot(`"insert into calendar_year (year_value, year_label) values (?, ?)"`)
            expect(ctx.lastParams).toMatchInlineSnapshot(`
              [
                2030,
                "FY2030",
              ]
            `)
            assertType<Exact<typeof affected, number>>()
            expect(affected).toBe(1)
        })
    })
})
